import pandas as pd
import re

def normalize_dye_lot(x):
    if pd.isna(x):
        return x
    s = str(x).strip()
    if s == "":
        return s
    # Extract the last run of digits as the lot number
    m = re.findall(r"(\d+)", s)
    if not m:
        return s.upper()
    num = int(m[-1])
    return f"DL-{num:04d}"

