import numpy as np

mapping = {
    'one': 1,
    'two': 2,
    'three': 3,
    'four': 4,
    'five': 5,
}
null_tokens = {'n/a', 'na', 'not sure', '', 'null', 'none'}

def clean_rating(x):
    if x is None or (isinstance(x, float) and np.isnan(x)):
        return np.nan
    s = str(x).strip().lower()
    if s in null_tokens:
        return np.nan
    if s in mapping:
        return float(mapping[s])
    # try numeric strings like '5', '4.0', etc.
    try:
        return float(s)
    except Exception:
        return np.nan

df['rating'] = df['rating'].apply(clean_rating)

